#!/usr/bin/env python3
"""
llm_experiments/llm_quality_check.py

Optional LLM-assisted quality check prototype.
Reads extracted PDF text from the results folder and asks GPT-4o-mini
whether each PDF conversion looks readable and well-formed.

Usage:
    # Install LLM dependencies first:
    pip install -r requirements-llm.txt

    # Set your API key:
    export OPENAI_API_KEY=sk-...

    # Run against all PDFs generated by the core test suite:
    python -m llm_experiments.llm_quality_check

Output:
    results/llm-quality-check/llm_verdicts.json
"""

import json
import csv
import os
import time
from datetime import datetime
from pathlib import Path

from dotenv import load_dotenv
from openai import OpenAI

try:
    import fitz
except ImportError:
    raise SystemExit("PyMuPDF is required. Run: pip install -r requirements-llm.txt")

load_dotenv()
client = OpenAI(api_key=os.environ.get("OPENAI_API_KEY"))

BASE_DIR = Path(__file__).resolve().parent.parent
PDF_DIR  = BASE_DIR / "results" / "generated-pdfs"
OUT_DIR  = BASE_DIR / "results" / "llm-quality-check"


def ask_llm(prompt: str) -> str:
    time.sleep(1)
    response = client.chat.completions.create(
        model="gpt-4o-mini",
        messages=[{"role": "user", "content": prompt}]
    )
    return response.choices[0].message.content


def extract_text(pdf_path: Path) -> str:
    doc = fitz.open(str(pdf_path))
    return "\n".join(page.get_text() for page in doc)


def check_pdf(pdf_path: Path) -> dict:
    text = extract_text(pdf_path)
    prompt = f"""You are a PDF quality checker. The following text was extracted from a converted PDF document.
Your job is to check if the conversion was successful — NOT to judge if the content is complete or comprehensive.

A conversion is PASS if:
- The text is readable and not garbled
- It contains recognizable words and structure
- It is not completely empty

A conversion is FAIL only if:
- The text is completely empty
- The text is garbled/unreadable (e.g. random symbols)
- The text is clearly corrupted

Reply with ONLY: PASS or FAIL, followed by one short reason (max 10 words).

Extracted text:
{text[:2000]}
"""
    verdict = ask_llm(prompt)
    return {
        "file": pdf_path.name,
        "verdict": verdict.strip(),
        "passed": verdict.strip().upper().startswith("PASS")
    }


def generate_csv(verdicts: list, out_path: Path):
    with open(out_path, "w", newline="", encoding="utf-8") as f:
        writer = csv.DictWriter(f, fieldnames=["file", "passed", "verdict"])
        writer.writeheader()
        writer.writerows(verdicts)


def generate_html(verdicts: list, out_path: Path):
    now = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    total = len(verdicts)
    passed = sum(1 for v in verdicts if v["passed"])
    failed = total - passed
    pass_rate = round((passed / total * 100) if total else 0, 1)

    rows = ""
    for v in verdicts:
        status_class = "pass" if v["passed"] else "fail"
        status_label = "✅ PASS" if v["passed"] else "❌ FAIL"
        rows += f"""
        <tr class="{status_class}">
            <td>{v['file']}</td>
            <td><span class="badge {status_class}">{status_label}</span></td>
            <td>{v['verdict']}</td>
        </tr>"""

    html = f"""<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>LLM Quality Check Report</title>
<style>
  * {{ box-sizing: border-box; margin: 0; padding: 0; }}
  body {{ font-family: 'Segoe UI', sans-serif; background: #f5f5f5; color: #222; padding: 2rem; }}
  h1 {{ font-size: 1.6rem; margin-bottom: 0.25rem; color: #1a1a2e; }}
  .subtitle {{ color: #666; font-size: 0.9rem; margin-bottom: 2rem; }}
  .kpi-row {{ display: flex; gap: 1rem; margin-bottom: 2rem; flex-wrap: wrap; }}
  .kpi {{ background: white; border-radius: 10px; padding: 1.2rem 2rem; flex: 1;
          box-shadow: 0 2px 8px rgba(0,0,0,0.07); text-align: center; min-width: 140px; }}
  .kpi .value {{ font-size: 2rem; font-weight: 700; }}
  .kpi .label {{ font-size: 0.8rem; color: #888; margin-top: 0.2rem; }}
  .kpi.green .value {{ color: #2e7d32; }}
  .kpi.red .value {{ color: #c62828; }}
  .kpi.blue .value {{ color: #1565c0; }}
  table {{ width: 100%; border-collapse: collapse; background: white;
           border-radius: 10px; overflow: hidden; box-shadow: 0 2px 8px rgba(0,0,0,0.07); }}
  thead {{ background: #1a1a2e; color: white; }}
  th {{ padding: 0.9rem 1rem; text-align: left; font-size: 0.85rem; letter-spacing: 0.05em; }}
  td {{ padding: 0.8rem 1rem; font-size: 0.9rem; border-bottom: 1px solid #eee; }}
  tr:last-child td {{ border-bottom: none; }}
  tr.pass td {{ background: #f9fff9; }}
  tr.fail td {{ background: #fff9f9; }}
  .badge {{ padding: 0.2rem 0.7rem; border-radius: 99px; font-size: 0.8rem; font-weight: 600; }}
  .badge.pass {{ background: #e8f5e9; color: #2e7d32; }}
  .badge.fail {{ background: #ffebee; color: #c62828; }}
  .footer {{ margin-top: 1.5rem; font-size: 0.8rem; color: #aaa; text-align: right; }}
  .note {{ background: #fff8e1; border-left: 4px solid #f9a825; padding: 0.8rem 1rem;
           border-radius: 4px; margin-bottom: 2rem; font-size: 0.88rem; color: #555; }}
</style>
</head>
<body>
  <h1>🔍 LLM Quality Check Report</h1>
  <p class="subtitle">Generated: {now} &nbsp;|&nbsp; Model: gpt-4o-mini &nbsp;|&nbsp; PDFs checked: {total}</p>
  <div class="note">
    ⚠️ <strong>Note:</strong> The LLM checks only whether PDFs are <em>readable</em> — not whether specific content is present.
    Regression detection is handled by the <strong>deterministic core test suite</strong>.
  </div>
  <div class="kpi-row">
    <div class="kpi green"><div class="value">{passed}</div><div class="label">PASSED</div></div>
    <div class="kpi red"><div class="value">{failed}</div><div class="label">FAILED</div></div>
    <div class="kpi blue"><div class="value">{pass_rate}%</div><div class="label">PASS RATE</div></div>
    <div class="kpi"><div class="value">{total}</div><div class="label">TOTAL PDFs</div></div>
  </div>
  <table>
    <thead><tr><th>PDF File</th><th>Verdict</th><th>LLM Reasoning</th></tr></thead>
    <tbody>{rows}</tbody>
  </table>
  <p class="footer">Markdown2Pdf.Console Testing Framework &mdash; LLM Exploratory Prototype</p>
</body>
</html>"""
    out_path.write_text(html, encoding="utf-8")


def main():
    OUT_DIR.mkdir(parents=True, exist_ok=True)
    pdfs = sorted(PDF_DIR.glob("*.pdf"))

    if not pdfs:
        print(f"No PDFs found in {PDF_DIR}. Run pytest tests first.")
        return

    print(f"Checking {len(pdfs)} PDFs with LLM...")
    verdicts = []
    for pdf in pdfs:
        result = check_pdf(pdf)
        verdicts.append(result)
        status = "✅ PASS" if result["passed"] else "❌ FAIL"
        print(f"  {status}  {result['file']}: {result['verdict']}")

    json_path = OUT_DIR / "llm_verdicts.json"
    csv_path  = OUT_DIR / "llm_verdicts.csv"
    html_path = OUT_DIR / "llm_report.html"

    json_path.write_text(json.dumps(verdicts, indent=2))
    generate_csv(verdicts, csv_path)
    generate_html(verdicts, html_path)

    print(f"\n✅ JSON  → {json_path}")
    print(f"✅ CSV   → {csv_path}")
    print(f"✅ HTML  → {html_path}")


if __name__ == "__main__":
    main()